<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Ubuntu Desktop Environment</title>
    <style>
        :root {
            --bg-color: #1a1a1a;
            --taskbar-bg: #2d2d2d;
            --window-bg: #303030;
            --text-color: #e0e0e0;
            --accent-color: #E95420; /* Ubuntu Orange */
            --border-color: #444;
        }

        * { box-sizing: border-box; user-select: none; }

        body, html { margin: 0; padding: 0; height: 100%; width: 100%; overflow: hidden; font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; background-color: var(--bg-color); color: var(--text-color); }

        /* Desktop Area */
        #desktop {
            width: 100vw;
            height: calc(100vh - 48px); /* Subtract taskbar height */
            position: relative;
            background: linear-gradient(135deg, #2c3e50 0%, #000000 100%);
            overflow: hidden;
        }

        /* Taskbar */
        #taskbar {
            height: 48px;
            width: 100%;
            background-color: var(--taskbar-bg);
            border-top: 1px solid var(--border-color);
            display: flex;
            align-items: center;
            padding: 0 10px;
            position: absolute;
            bottom: 0;
        }

        .launcher {
            width: 48px;
            height: 48px;
            margin-right: 10px;
            border-radius: 8px;
            display: flex;
            justify-content: center;
            align-items: center;
            cursor: pointer;
            transition: background 0.2s;
            font-size: 24px;
        }

        .launcher:hover { background-color: #444; }
        .launcher.active { border-bottom: 3px solid var(--accent-color); }

        /* Window Styling */
        .window {
            position: absolute;
            top: 50px;
            left: 50px;
            width: 600px;
            min-height: 400px; /* > 360x240 requirement */
            background-color: var(--window-bg);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: flex;
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #555;
        }

        .window-header {
            height: 32px;
            background-color: #404040;
            display: flex;
            align-items: center;
            padding: 0 10px;
            cursor: default; /* Visual only */
        }

        .window-title { font-size: 13px; margin-left: 8px; }

        .win-close {
            width: 24px;
            height: 24px;
            border-radius: 50%;
            background-color: #c0392b;
            color: white;
            display: flex;
            justify-content: center;
            align-items: center;
            cursor: pointer;
            font-weight: bold;
            font-size: 16px;
        }
        .win-close:hover { background-color: #e74c3c; }

        /* Files App Specifics */
        #files-window { z-index: 10; }

        #files-toolbar {
            padding: 8px;
            background-color: #252526;
            border-bottom: 1px solid var(--border-color);
            display: flex;
            align-items: center;
            gap: 10px;
        }

        #files-up {
            background-color: #3c3c3c;
            border: none;
            color: white;
            padding: 4px 8px;
            cursor: pointer;
            border-radius: 4px;
        }
        #files-up:hover { background-color: #505050; }

        #files-path { font-family: monospace; color: #aaa; font-size: 13px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; max-width: 200px;}

        #files-list {
            flex: 1;
            padding: 10px;
            overflow-y: auto;
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
            gap: 5px;
            align-content: start;
        }

        .fs-item {
            background-color: #3c3c3c;
            padding: 10px;
            text-align: center;
            border-radius: 4px;
            cursor: pointer;
            font-size: 14px;
            transition: background 0.1s;
        }

        .fs-item:hover { background-color: #505050; }
        .fs-item.folder { color: #61dafb; } /* Blue for folders */
        .fs-item.file { color: #fff; }

        /* Notepad App Specifics */
        #notepad-window { z-index: 20; }

        #tabs-container {
            background-color: #3c3c3c;
            display: flex;
            align-items: center;
            padding-top: 5px;
            border-bottom: 1px solid var(--border-color);
            height: 30px;
        }

        .tab {
            background-color: #2d2d2d;
            padding: 4px 12px;
            margin-right: 2px;
            border-radius: 4px 4px 0 0;
            font-size: 13px;
            cursor: pointer;
            max-width: 150px;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
            border: 1px solid transparent;
        }

        .tab.active { background-color: var(--window-bg); border-bottom: 1px solid var(--window-bg); color: #fff; }

        #new-tab-btn {
            margin-left: auto;
            background: none;
            border: none;
            color: #aaa;
            cursor: pointer;
            font-size: 18px;
            padding: 0 5px;
        }
        #new-tab-btn:hover { color: white; }

        #editor-container { flex: 1; display: flex; flex-direction: column; }

        #editor {
            flex: 1;
            background-color: var(--window-bg);
            color: #ddd;
            border: none;
            resize: none;
            padding: 10px;
            font-family: 'Consolas', 'Monaco', monospace;
            font-size: 14px;
            outline: none;
        }

    </style>
</head>
<body>

<div id="desktop">

    <!-- Files Window -->
    <div id="files-window" class="window" style="display:none;">
        <div class="window-header">
            <span class="window-title">Files</span>
            <div class="win-close" onclick="toggleWindow('files-window')">✕</div>
        </div>
        <div id="files-toolbar">
            <button id="files-up" title="Go Up">↑</button>
            <span id="files-path">/</span>
        </div>
        <div id="files-list"></div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window" style="display:none;">
        <div class="window-header">
            <span class="window-title">Notepad</span>
            <div class="win-close" onclick="toggleWindow('notepad-window')">✕</div>
        </div>
        <div id="tabs-container">
            <!-- Tabs injected here -->
            <button id="new-tab-btn" title="New Tab">+</button>
        </div>
        <div id="editor-container">
            <textarea id="editor" placeholder="Type here..."></textarea>
        </div>
    </div>

</div>

<div id="taskbar">
    <div class="launcher" id="open-files" title="Open Files App">📁</div>
    <div class="launcher" id="open-notepad" title="Open Notepad App">📝</div>
</div>

<script>
    // --- State Management ---

    // Fake Filesystem Structure
    const fileSystem = {
        "/": ["bin", "etc", "home", "usr", "var"],
        "/bin": [],
        "/etc": [],
        "/home": ["user"],
        "/home/user": ["Documents", "Downloads", "Pictures", "notes.txt", "readme.md"],
        "/usr": ["local", "share"],
        "/usr/local": ["bin", "lib"],
        "/usr/share": ["doc", "icons"],
        "/var": ["log", "cache"],
        "/var/log": ["syslog", "auth.log"],
        "/var/cache": []
    };

    // Notepad State
    let notepadTabs = []; 
    let activeTabId = null;

    // --- Initialization ---

    window.onload = function() {
        loadNotepadState();
        renderFiles("/");

        // Event Listeners
        document.getElementById('open-files').addEventListener('click', () => toggleWindow('files-window'));
        document.getElementById('open-notepad').addEventListener('click', () => toggleWindow('notepad-window'));

        document.getElementById('files-up').addEventListener('click', goUp);
        document.getElementById('new-tab-btn').addEventListener('click', createNewTab);

        // Double click on files list
        const fileList = document.getElementById('files-list');
        fileList.addEventListener('dblclick', (e) => {
            if(e.target.classList.contains('fs-item')) {
                const name = e.target.innerText;
                navigate(name);
            }
        });
    };

    // --- Window Management ---

    function toggleWindow(id) {
        const win = document.getElementById(id);
        if (win.style.display === 'none') {
            win.style.display = 'flex';
            bringToFront(win);
        } else {
            win.style.display = 'none';
        }
    }

    function bringToFront(element) {
        // Simple z-index bump for active window
        const allWindows = document.querySelectorAll('.window');
        allWindows.forEach(w => w.style.zIndex = 10);
        element.style.zIndex = 20;
    }

    // --- Files App Logic ---

    function renderFiles(path) {
        const listContainer = document.getElementById('files-list');
        const pathDisplay = document.getElementById('files-path');

        listContainer.innerHTML = '';
        pathDisplay.innerText = path;

        const items = fileSystem[path];
        if (!items) return; // End of tree

        items.forEach(name => {
            const item = document.createElement('div');
            item.className = 'fs-item folder'; // Assume folders for simplicity in root, though we have files too
            item.innerText = name;

            // Check if it's a file or folder based on existence in object keys (simplified check)
            // In this structure, arrays hold children. If key exists, it has content.
            // We'll treat everything as folders for navigation unless it's explicitly a file in the list logic below.
            // Actually, let's just render them all as folders visually but handle files if needed.
            // For this spec, we will treat everything in the array as navigable folders for simplicity 
            // OR distinguish by checking if they are actually files (e.g. "notes.txt").

            if(name.endsWith('.txt') || name.endsWith('.md')) {
                item.classList.remove('folder');
                item.classList.add('file');
            }

            listContainer.appendChild(item);
        });
    }

    function navigate(targetName) {
        const currentPath = document.getElementById('files-path').innerText;

        // Construct new path
        let newPath = currentPath + "/" + targetName;

        // Handle root case if we were at / and clicked something (though logic handles this naturally)
        // Check if valid
        if (fileSystem[newPath]) {
            renderFiles(newPath);
        } else {
            console.log("Cannot navigate to " + newPath);
        }
    }

    function goUp() {
        const currentPath = document.getElementById('files-path').innerText;

        // Remove last segment
        let parts = currentPath.split('/');
        parts.pop(); // remove last
        let parentPath = parts.join('/');

        if (parentPath === "") parentPath = "/";

        renderFiles(parentPath);
    }

    // --- Notepad App Logic ---

    function loadNotepadState() {
        const savedTabs = localStorage.getItem('ubuntu_notepad_tabs');
        if (savedTabs) {
            notepadTabs = JSON.parse(savedTabs);

            // Restore active tab
            if (notepadTabs.length > 0) {
                activeTabId = notepadTabs[0].id;
                renderNotepad();
            } else {
                createNewTab(); // Empty state fallback
            }
        } else {
            createNewTab();
        }
    }

    function saveNotepadState() {
        localStorage.setItem('ubuntu_notepad_tabs', JSON.stringify(notepadTabs));
    }

    function createNewTab() {
        const id = 'tab-' + Date.now();
        const tabData = {
            id: id,
            title: 'Untitled',
            content: ''
        };

        notepadTabs.push(tabData);
        renderNotepad();
        saveNotepadState();
    }

    function switchTab(id) {
        activeTabId = id;
        renderNotepad();
    }

    function closeTab(e, id) {
        e.stopPropagation(); // Prevent triggering tab click

        const index = notepadTabs.findIndex(t => t.id === id);

        if (index > -1) {
            notepadTabs.splice(index, 1);

            // If we closed the active tab, switch to another or create new
            if (notepadTabs.length === 0) {
                createNewTab();
            } else if (activeTabId === id) {
                const newIndex = Math.max(0, index - 1);
                activeTabId = notepadTabs[newIndex].id;
            }

            renderNotepad();
            saveNotepadState();
        }
    }

    function renderNotepad() {
        const container = document.getElementById('tabs-container');
        const editor = document.getElementById('editor');

        // Clear existing tabs (except the + button)
        const btn = document.getElementById('new-tab-btn');
        while(container.children.length > 1) {
            container.removeChild(container.firstChild);
        }

        notepadTabs.forEach(tab => {
            const tabEl = document.createElement('div');
            tabEl.className = 'tab';
            if (tab.id === activeTabId) tabEl.classList.add('active');

            // Title with close button
            tabEl.innerHTML = `${tab.title} <span style="float:right; font-size:10px; cursor:pointer;" onclick="closeTab(event, '${tab.id}')">×</span>`;

            tabEl.addEventListener('click', () => switchTab(tab.id));
            container.appendChild(tabEl);
        });

        // Update editor content
        if (activeTabId) {
            const activeTab = notepadTabs.find(t => t.id === activeTabId);
            if (activeTab) {
                editor.value = activeTab.content;
            }
        }
    }

    // Editor Input Listener
    document.getElementById('editor').addEventListener('input', function() {
        if (!activeTabId) return;

        const tab = notepadTabs.find(t => t.id === activeTabId);
        if (tab) {
            tab.content = this.value;
            saveNotepadState();

            // Update title if empty
            if(this.value.trim() === "") {
                tab.title = 'Untitled';
                renderNotepad(); // Re-render to update title text
            } else {
                // Optional: Auto-update title on first char? 
                // Let's keep it simple, only update if explicitly needed or just leave as Untitled until saved/changed logic.
                // For this spec, let's just save content.
            }
        }
    });

</script>
</body>
</html>
